const body = $json.body || {}

const eventText = String(body.event_text || body.text || body.message || '').trim();
const source = String(body.source || 'poke').trim();
const timestamp = body.timestamp || new Date().toISOString();
const tags = Array.isArray(body.tags) ? body.tags.map((t) => String(t).trim()).filter(Boolean) : [];
const confidence = body.confidence !== undefined ? Number(body.confidence) : 0.72;

return {
  event_text: eventText,
  source,
  timestamp,
  tags,
  confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0.72,
  raw: body
};

const store = $getWorkflowStaticData('global');
if (!Array.isArray(store.memorySignalQueue)) {
  store.memorySignalQueue = [];
}

const signal = {
  event_text: $json.event_text,
  source: $json.source,
  timestamp: $json.timestamp,
  tags: $json.tags || [],
  confidence: $json.confidence ?? 0.72
};

if (signal.event_text) {
  store.memorySignalQueue.push(signal);
}

if (store.memorySignalQueue.length > 500) {
  store.memorySignalQueue = store.memorySignalQueue.slice(-500);
}

return {
  queued: Boolean(signal.event_text),
  pending_count: store.memorySignalQueue.length,
  accepted_signal: signal
};

const cfg = $input.first().json;
const store = $getWorkflowStaticData('global');
const queued = Array.isArray(store.memorySignalQueue) ? store.memorySignalQueue : [];
const batch = queued.slice(-100);

if (queued.length > 100) {
  store.memorySignalQueue = queued.slice(0, queued.length - 100);
} else {
  store.memorySignalQueue = [];
}

return [{
  json: {
    run_timestamp: cfg.run_timestamp || new Date().toISOString(),
    notion_token: cfg.notion_token,
    memory_db_id: cfg.memory_db_id,
    queued_count: batch.length,
    signals: batch
  }
}];

const input = $input.first().json;
const signals = Array.isArray(input.signals) ? input.signals : [];

if (!signals.length) {
  return [{
    json: {
      noCandidates: true,
      run_timestamp: input.run_timestamp,
      queued_count: 0
    }
  }];
}

const typeRules = [
  { type: 'book', regex: /\b(book|reading|read|author|novel)\b/i, stale: 30 },
  { type: 'preference', regex: /\b(like|love|hate|prefer|favorite)\b/i, stale: 180 },
  { type: 'project', regex: /\b(project|working on|building|shipping|launch)\b/i, stale: 45 },
  { type: 'person', regex: /\b(friend|mom|dad|partner|colleague|team)\b/i, stale: 120 },
  { type: 'health', regex: /\b(sleep|health|doctor|exercise|energy|anxious|tired)\b/i, stale: 14 },
];

function classify(text) {
  for (const rule of typeRules) {
    if (rule.regex.test(text)) return { type: rule.type, stale: rule.stale };
  }
  return { type: 'fact', stale: 90 };
}

function extractSubject(text) {
  const cleaned = text.replace(/\s+/g, ' ').trim();
  if (!cleaned) return 'general memory';

  const separators = [' because ', ' but ', ' and ', '.', '!', '?'];
  let subject = cleaned;
  for (const sep of separators) {
    const idx = subject.toLowerCase().indexOf(sep.trim());
    if (idx > 20) {
      subject = subject.slice(0, idx);
      break;
    }
  }

  if (subject.length > 80) subject = subject.slice(0, 80).trim();
  return subject || 'general memory';
}

const dedup = new Map();
for (const signal of signals) {
  const text = String(signal.event_text || '').trim();
  if (!text) continue;

  const cls = classify(text);
  const subject = extractSubject(text);
  const key = (cls.type + '::' + subject).toLowerCase().replace(/[^a-z0-9:]+/g, '_').replace(/^_+|_+$/g, '');

  const candidate = {
    memory_key: key,
    type: cls.type,
    subject,
    summary: text.slice(0, 500),
    confidence: Number.isFinite(Number(signal.confidence)) ? Math.max(0, Math.min(1, Number(signal.confidence))) : 0.72,
    last_seen: signal.timestamp || new Date().toISOString(),
    stale_after_days: cls.stale,
    status: 'active',
    source: signal.source || 'poke',
    tags: Array.isArray(signal.tags) ? signal.tags.slice(0, 10) : [],
    notion_token: input.notion_token,
    memory_db_id: input.memory_db_id,
    run_timestamp: input.run_timestamp
  };

  dedup.set(key, candidate);
}

const out = Array.from(dedup.values())
  .slice(0, 10)
  .map((item) => ({ json: item }));

if (!out.length) {
  return [{
    json: {
      noCandidates: true,
      run_timestamp: input.run_timestamp,
      queued_count: signals.length
    }
  }];
}

return out;

const runTimestamp = $input.first().json.run_timestamp || new Date().toISOString();
return [{
  json: {
    message: `[system] memory distiller daily check\n\nRun timestamp: ${runTimestamp}\nResult: no queued memory signals to distill today.`
  }
}];

const existingPageId = Array.isArray($json.results) && $json.results.length > 0 ? $json.results[0].id : null;

let queryError = null;
if ($json.error) {
  const raw = $json.error;
  queryError = typeof raw === 'string' ? raw : (raw.message || JSON.stringify(raw));
}

return {
  ...$json,
  existingPageId,
  queryError
};

const source = $('Decide Create or Update').item.json;
const action = source.existingPageId ? 'updated' : 'created';

let error = null;
if ($json.error) {
  const raw = $json.error;
  error = typeof raw === 'string' ? raw : (raw.message || JSON.stringify(raw));
}

return {
  action,
  ok: !error,
  error,
  page_id: $json.id || source.existingPageId || null,
  memory_key: source.memory_key,
  type: source.type,
  subject: source.subject
};

const rows = $input.all().map((i) => i.json);
const created = rows.filter((r) => r.ok && r.action === 'created');
const updated = rows.filter((r) => r.ok && r.action === 'updated');
const failed = rows.filter((r) => !r.ok);

const sample = rows.slice(0, 8).map((r) => {
  const status = r.ok ? (r.action === 'created' ? 'CREATED' : 'UPDATED') : 'FAILED';
  return `- ${status}: [${r.type}] ${r.subject}`;
}).join('\n');

const message = `[system] memory distiller daily check\n\nTotal candidates: ${rows.length}\nCreated: ${created.length}\nUpdated: ${updated.length}\nFailed: ${failed.length}\n\n${sample || '- No candidate details'}\n\n${failed.length ? 'Status: some memory upserts failed. Check n8n execution logs.' : 'Status: memory distillation completed successfully.'}`;

return [{ json: { message } }];
